arguments.newText:
/* Check for sensor timeout first */
 if (!controller->has_valid_sensor) {
     controller->last_valid_sensor_ms = input.now_ms;
 }

 switch (input.kind) {
 case CONTROLLER_INPUT_TEMPERATURE:
     controller->has_valid_sensor = true;
     controller->last_temperature_c = input.temperature_c;
     controller->last_valid_sensor_ms = input.now_ms;

     /* Check for stale sensor data (> 1000ms without valid frame) */
     if (input.now_ms > controller->last_valid_sensor_ms + CONTROLLER_SENSOR_TIMEOUT_MS) {
         controller->has_valid_sensor = false;
         controller_set_safe_off(controller);
     } else {
         /* Apply control policy based on temperature */
         int temp = input.temperature_c;

         if (temp < CONTROLLER_TEMP_LOW_THRESHOLD) {
             /* TEMP < 47: turn heater on, enter HEATING state */
             controller->heater_on = true;
             controller->state = CONTROLLER_STATE_HEATING;
         } else if (temp > CONTROLLER_TEMP_HIGH_THRESHOLD) {
             /* TEMP > 52: turn heater off, enter SAFE_OFF state */
             controller_set_safe_off(controller);
         } else if (temp < 50) {
             /* 47 <= TEMP < 50: hold previous safe actuator state, HOLDING */
             controller->state = CONTROLLER_STATE_HOLDING;
         } else if (temp >= 50 && temp <= CONTROLLER_TEMP_HIGH_THRESHOLD) {
             /* 50 <= TEMP <= 52: check if rising */
             bool is_rising = false;
             if (controller->has_valid_sensor && controller->last_temperature_c > 0) {
                 /* Compare current with previous valid temperature */
                 int prev_temp = controller->last_temperature_c;
                 /* We need to track the previous temp before updating */
                 /* For now, use a simple approach: check if we just came from lower */
                 is_rising = (temp > prev_temp);
             }

             if (is_rising) {
                 /* Rising temperature near upper band: turn heater off early */
                 controller->heater_on = false;
                 controller->state = CONTROLLER_STATE_HOLDING;
             } else {
                 /* Not rising: hold previous safe actuator state */
                 controller->state = CONTROLLER_STATE_HOLDING;
             }
         } else {
             /* Fallback to safe off */
             controller_set_safe_off(controller);
         }
     }
     break;
 case CONTROLLER_INPUT_SENSOR_TIMEOUT:
 case CONTROLLER_INPUT_INVALID_TEMPERATURE:
     controller->has_valid_sensor = false;
     controller_set_safe_off(controller);
     break;
 case CONTROLLER_INPUT_NONE:
 default:
     /* Check for timeout on NONE input - stale sensor data */
     if (controller->has_valid_sensor &&
         input.now_ms > controller->last_valid_sensor_ms + CONTROLLER_SENSOR_TIMEOUT_MS) {
         controller_set_safe_off(controller);
         output.timed_out = true;
     } else {
         /* Hold previous state on NONE input (idle step) */
         controller->state = CONTROLLER_STATE_HOLDING;
     }
     break;
 }

 output.heater_on = controller->heater_on;
 output.state = controller->state;
 output.state_name = controller_state_name(controller->state);
 output.changed = (previous_heater_on != controller->heater_on) || (previous_state != controller->state);

 return output;

